#include <stdio.h>
#include <stdlib.h>

int main(void) {
    int nums[5], pos[5], score = 0;
    for (int i = 0; i < 5; i++) {
        do {
            nums[i] = rand() % 10 + 1;
        } while (i > 0 && nums[i] == nums[i-1]);
    }
    for (int i = 0; i < 5; i++) pos[i] = -1;
    while (1) {
        printf("Numbers: ");
        for (int i = 0; i < 5; i++) {
            if (pos[i] == -1) printf("* ");
            else printf("%d ", nums[pos[i]]);
        }
        printf("\nPick: ");
        int p, g;
        scanf("%d %c", &p, &g);
        if (p < 1 || p > 5 || pos[p-1] != -1) continue;
        if ((g == 'E' && nums[p-1] % 2 == 0) || (g == 'O' && nums[p-1] % 2 != 0)) {
            score += 5;
            pos[p-1] = nums[p-1];
        }
        printf("Win: %s, Points: %d, Pick: %d\n", g == 'E' ? "Even" : "Odd", score, p);
        if (score == 25) break;
    }
    printf("Final Score: %d\n", score);
    return 0;
}
